/// <summary>
///    Gets the sum of <c>AmountMST</c> for each customer transaction in the given <c>ETG_CustProvisionalBalanceTmpValue</c>
/// </summary>
private void getAccountingCurrencyBalance(ETG_CustProvisionalBalanceTmpValue _tmpValue, TransDate _fromDate, int _creditOrDebitSign)
{
    CustTrans custTrans;
    CustTrans_W custTrans_W;
    DimensionAttributeValueSetItem  dimensionAttributeValueSetItem;
    DimensionAttributeValue              dimensionAttributeValue;
    DimensionAttribute                       dimensionAttribute;

    if(isPublicSectorScenario)
    {
        /*
        insert_recordset _tmpValue
            (AccountNum, Location, PostingProfile, Amount)
            select AccountNum, Location
            from custProvisionalBalanceTmpProcessing
                group by AccountNum, Location
            join PostingProfile, sum(AmountMST) from custTrans
                group by PostingProfile,DefaultDimension
                where custTrans.AccountNum == custProvisionalBalanceTmpProcessing.AccountNum
                    && custTrans.PostingProfile == custProvisionalBalanceTmpProcessing.PostingProfile
                    && custTrans.TransDate >= _fromDate
                    && custTrans.TransDate <= toDate
                    && (((_creditOrDebitSign * custTrans.AmountMST) > 0 && !custTrans.Correct) || ((_creditOrDebitSign * custTrans.AmountMST) < 0 && custTrans.Correct))
            join dimensionAttributeValueSetItem
        join dimensionAttributeValue
        join dimensionAttribute
        where dimensionAttributeValueSetItem.DimensionAttributeValue    == dimensionAttributeValue.RecId
             && dimensionAttributeValue.DimensionAttribute                == dimensionAttribute.RecId
             && dimensionAttribute.Name                                                == 'Locations'
             && dimensionAttributeValueSetItem.DimensionAttributeValueSet == custTrans.DefaultDimension
             && dimensionAttributeValueSetItem.DisplayValue == custProvisionalBalanceTmpProcessing.Location
            join custProvisionalBalanceTmpBCCriteria
                where custProvisionalBalanceTmpBCCriteria.CustBillingClassification == custTrans.CustBillingClassification
            notexists join custTrans_W
                where custTrans_W.CustTrans == custTrans.RecId
                    && custTrans_W.InvoicePostingType_RU == SalesInvoicePostingType_RU::GoodsInRoute;
        */

        while             select AccountNum,Location, PostingProfile
        from custProvisionalBalanceTmpProcessing
            //group by AccountNum,Location
            Where  custProvisionalBalanceTmpProcessing.Location != ""
        join PostingProfile, DefaultDimension, TransDate, AmountMST from custTrans
            //group by PostingProfile, DefaultDimension
            where custTrans.AccountNum == custProvisionalBalanceTmpProcessing.AccountNum
                && custTrans.PostingProfile == custProvisionalBalanceTmpProcessing.PostingProfile
                && custTrans.TransDate >= _fromDate
                && custTrans.TransDate <= toDate
